from dataclasses import dataclass
from typing import Literal

StoryType = Literal["epic", "story", "spike", "acceptance_criterion"]

@dataclass
class BacklogItem:
    item_type: StoryType
    title: str
    description: str
    source_id: str

def board_to_backlog(board: EventStormingBoard) -> list[BacklogItem]:
    items: list[BacklogItem] = []

    contexts = board.grouped_by_context()
    for ctx_name, stickies in contexts.items():
        if ctx_name == "Unassigned":
            continue
        ctx_events = [s for s in stickies if s.sticky_type == StickyType.EVENT]
        desc = "Handles: " + ", ".join(s.text for s in ctx_events[:3])
        items.append(BacklogItem("epic", f"[{ctx_name}] Agent Capability", desc, ctx_name))

    for s in board.stickies.values():
        if s.sticky_type == StickyType.POLICY:
            items.append(BacklogItem(
                "acceptance_criterion", s.text,
                f"Policy from event storming: {s.text}", s.id
            ))

    for h in board.hotspots():
        items.append(BacklogItem(
            "spike", f"Spike: resolve '{h.text}'",
            "Unresolved risk identified during event storming.", h.id
        ))

    return items

backlog = board_to_backlog(board)
print("Generated backlog items:")
for item in backlog:
    print(f"  [{item.item_type.upper():>20}] {item.title}")
